import React from 'react';
import { useNavigate } from 'react-router-dom';

const BlogCard = ({ blog }) => {
  const navigate = useNavigate();

  // ✅ Prevent crash if blog is undefined or not an object
  if (!blog || typeof blog !== 'object') return null;

  const shortContent = blog.content?.length > 120
    ? blog.content.substring(0, 120) + '...'
    : blog.content || 'No content available.';

  return (
    <div
      onClick={() => navigate(`/blog/${blog.id}`)}
      className="bg-white rounded-lg shadow hover:shadow-md transition cursor-pointer overflow-hidden"
    >
      {/* Blog Image */}
      <img
        src={blog.image_url || 'https://via.placeholder.com/600x300?text=Blog+Image'}
        alt={blog.title || 'Blog Title'}
        className="w-full h-48 object-cover"
      />

      {/* Blog Info */}
      <div className="p-4">
        <h3 className="text-lg font-semibold text-blue-800 mb-2">
          {blog.title || 'Untitled Blog'}
        </h3>

        <p className="text-sm text-gray-600 mb-1">
          {blog.category_name || 'General'} •{' '}
          {blog.created_at
            ? new Date(blog.created_at).toLocaleDateString()
            : 'Unknown Date'}
        </p>

        <p className="text-gray-700 text-sm">{shortContent}</p>
      </div>
    </div>
  );
};

export default BlogCard;
